meta.script:
(function(){
  const gameUrl = "https://cdn.jsdelivr.net/gh/un-zynq/singlefilegames/drift-hunters-pro.html";

  fetch(gameUrl)
    .then(response => response.text())
    .then(html => {
      const iframe = document.getElementById('gameFrame');
      const doc = iframe.contentWindow.document;
      doc.open();
      doc.write(html);
      doc.close();

      // Wacht tot de DOM geladen is en patch dan de Unity loader
      iframe.onload = function() {
        try {
          const iframeWin = iframe.contentWindow;
          const iframeDoc = iframe.contentDocument;

          // Patch de URL constructor in de iframe
          const patchScript = iframeDoc.createElement('script');
          patchScript.textContent = `
            (function() {
              if (window.URL) {
                const OriginalURL = window.URL;
                window.URL = function(url, base) {
                  if (typeof url === 'string' && url.startsWith('blob:')) {
                    return { href: url, toString: function() { return url; } };
                  }
                  try {
                    return new OriginalURL(url, base);
                  } catch(e) {
                    return { href: url, toString: function() { return url; } };
                  }
                };
                window.URL.createObjectURL = OriginalURL.createObjectURL.bind(OriginalURL);
                window.URL.revokeObjectURL = OriginalURL.revokeObjectURL.bind(OriginalURL);
                window.URL.prototype = OriginalURL.prototype;
              }
            })();
          `;
          iframeDoc.head.appendChild(patchScript);

          // Patch createUnityInstance als die bestaat
          const patchUnityScript = iframeDoc.createElement('script');
          patchUnityScript.textContent = `
            (function() {
              if (typeof window.createUnityInstance === 'function') {
                const originalCUI = window.createUnityInstance;
                window.createUnityInstance = function(canvas, config, progress) {
                  if (config && config.dataUrl && typeof config.dataUrl === 'string' && config.dataUrl.startsWith('blob:')) {
                    config.dataUrl = config.dataUrl.toString();
                  }
                  return originalCUI(canvas, config, progress);
                };
              }
            })();
          `;
          iframeDoc.head.appendChild(patchUnityScript);

        } catch(e) {
          console.log("Patch error:", e);
        }
      };
    })
    .catch(error => {
      const iframe = document.getElementById('gameFrame');
      const doc = iframe.contentWindow.document;
      doc.open();
      doc.write('Fetch error: ' + error.message + '');
      doc.close();
    });
})();
